const output = $json.output;
const now = new Date();
const dateStr = `${now.getFullYear()}${String(now.getMonth()+1).padStart(2,'0')}${String(now.getDate()).padStart(2,'0')}`;
const idx = Math.floor(Math.random()*900)+100;
const dateFormatted = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const timeFormatted = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
const fileContent = `# ☀️ Morning Dev Note

**Date:** ${dateFormatted}
**Time:** ${timeFormatted}
**Mood:** Learning mode 🧠

---

## 💡 What I Learned Today

${output}

---

*Part of my [Daily-Upload](https://github.com/gaurav712-gujjar/Daily-Upload) streak — 3 notes a day, every day.*
`;
return [{ json: { filename: `notes/${now.getFullYear()}/${String(now.getMonth()+1).padStart(2,'0')}/${dateStr}_morning_${idx}.md`, content: Buffer.from(fileContent).toString('base64'), message: `☀️ morning note [${now.toDateString()}]`, author_name: 'gaurav gujjar', author_email: 'gujjargaurav712@gmail.com', noteText: output } }];

